    ['name' => 'Emma Goldman', 'first_name' => 'Emma', 'last_name' => 'Goldman', 'aka' => 'Red Emma', 'gender' => 'Female', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1869-06-27', 'death_date' => '1940-05-14', 'description' => 'The most prominent anarchist in Wilson-era America: fiery orator, editor of Mother Earth (1906–1917), tireless advocate for free speech, birth control, women\'s emancipation, and labor militancy. Born to Orthodox Jewish family in Kaunas, Lithuania; emigrated 1885; radicalized by 1887 Haymarket executions. With Alexander Berkman co-founded the No-Conscription League in May 1917; arrested June 15, 1917; convicted by Judge Julius M. Mayer; sentenced to 2 years federal prison and $10,000 fines. Served at Missouri State Penitentiary in Jefferson City. Stripped of derivative citizenship and deported on the USAT Buford ("Soviet Ark") to Soviet Russia on December 21, 1919. Broke with Bolshevism after Kronstadt (1921); died in Toronto 1940.', 'affiliation' => ['No-Conscription League', 'Mother Earth (publisher)', 'Anarchist movement'], 'cases' => [['institution' => ['name' => 'Missouri State Penitentiary, Jefferson City', 'city' => 'Jefferson City', 'state' => 'Missouri'], 'arrest_date' => '1917-06-15', 'sentenced_date' => '1917-07-09', 'release_date' => '1919-09-27', 'sentence' => '2 years federal prison + $10,000 fine; deported on Soviet Ark Dec 21, 1919', 'convicted' => 'Yes', 'judge' => 'Hon. Julius Marshuetz Mayer', 'charges' => 'Conspiracy to obstruct the draft (Selective Service Act of 1917 / Espionage Act of 1917).']]],
    ['name' => 'Alexander Berkman', 'first_name' => 'Alexander', 'last_name' => 'Berkman', 'aka' => 'Sasha; Ovsei Osipovich Berkman', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1870-11-21', 'death_date' => '1936-06-28', 'description' => 'Emma Goldman\'s lifelong comrade and one of the foremost American anarchists. Born to wealthy Lithuanian-Jewish family; immigrated ~1887. In 1892 carried out a propaganda-of-the-deed attentat against Henry Clay Frick during the Homestead steel strike, serving 14 years in Pennsylvania\'s Western Penitentiary. With Goldman co-founded the No-Conscription League in 1917; convicted with her under Judge Mayer; served two years at Atlanta, including seven months in solitary for protesting beatings. Released Oct 1, 1919; deported on USAT Buford Dec 21, 1919. Wrote "The Bolshevik Myth" (1925); committed suicide in Nice 1936.', 'affiliation' => ['No-Conscription League', 'Mother Earth', 'The Blast (editor)'], 'cases' => [['institution' => ['name' => 'U.S. Penitentiary Atlanta', 'city' => 'Atlanta', 'state' => 'Georgia'], 'arrest_date' => '1917-06-15', 'sentenced_date' => '1917-07-09', 'release_date' => '1919-10-01', 'sentence' => '2 years federal prison + $10,000 fine; deported on Soviet Ark Dec 21, 1919', 'convicted' => 'Yes', 'judge' => 'Hon. Julius Marshuetz Mayer', 'charges' => 'Conspiracy to obstruct the draft.']]],
    ['name' => 'Jacob Abrams', 'first_name' => 'Jacob', 'last_name' => 'Abrams', 'aka' => 'Jack Abrams', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1886-01-01', 'death_date' => '1953-12-15', 'description' => 'Russian-Jewish anarchist bookbinder and lead defendant in the landmark First Amendment case Abrams v. United States, 250 U.S. 616 (1919). On August 22-23, 1918 he and four others were arrested in New York for throwing Yiddish and English leaflets from a Lower East Side rooftop denouncing Wilson\'s deployment of U.S. troops to Soviet Russia. Convicted Oct 23, 1918 under the Sedition Act; sentenced to 20 years and $1,000 fine. SCOTUS upheld 7-2 (famous Holmes/Brandeis "marketplace of ideas" dissent). Served roughly 3 years at Atlanta; deported to Soviet Russia aboard SS Estonia Nov 24, 1921; later left USSR for Mexico, where he died 1953.', 'affiliation' => ['Frayhayt anarchist group'], 'cases' => [['institution' => ['name' => 'U.S. Penitentiary Atlanta — Abrams trial (S.D.N.Y.)', 'city' => 'Atlanta', 'state' => 'Georgia'], 'arrest_date' => '1918-08-23', 'sentenced_date' => '1918-10-25', 'release_date' => '1921-11-24', 'sentence' => '20 years federal prison + $1,000 fine; deported to USSR Nov 24, 1921', 'convicted' => 'Yes; affirmed Abrams v. US 250 U.S. 616 (1919)', 'judge' => 'Hon. Henry DeLamar Clayton Jr.', 'charges' => 'Conspiracy to violate Sedition Act of 1918 (amending Espionage Act of 1917) — 4 counts.']]],
    ['name' => 'Mollie Steimer', 'first_name' => 'Mollie', 'last_name' => 'Steimer', 'aka' => 'Marthe Alperine', 'gender' => 'Female', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1897-11-21', 'death_date' => '1980-07-23', 'description' => 'Immigrated from Ukraine to New York at age 15 in 1913; worked in a garment factory; joined the Yiddish-anarchist Frayhayt group by 1917. Twenty years old at her arrest; the youngest and only female defendant in Abrams v. United States. Convicted Oct 25, 1918; sentenced to 15 years federal prison plus $500 fine. Refused to flee with her co-defendants out of solidarity with workers who had raised her bond. Deported to Soviet Russia Nov 24, 1921; expelled from USSR 1923 for protesting Bolshevik repression of anarchists. Lived in Berlin and Paris before fleeing to Mexico City in 1942.', 'affiliation' => ['Frayhayt anarchist group'], 'cases' => [['institution' => ['name' => 'Missouri State Penitentiary — Abrams trial (S.D.N.Y.)', 'city' => 'Jefferson City', 'state' => 'Missouri'], 'arrest_date' => '1918-08-23', 'sentenced_date' => '1918-10-25', 'release_date' => '1921-11-24', 'sentence' => '15 years federal prison + $500 fine; deported to USSR Nov 24, 1921; expelled to Germany 1923; later Mexico 1942', 'convicted' => 'Yes; affirmed Abrams v. US 250 U.S. 616 (1919)', 'judge' => 'Hon. Henry DeLamar Clayton Jr.', 'charges' => 'Conspiracy to violate Sedition Act of 1918.']]],
    ['name' => 'Hyman Lachowsky', 'first_name' => 'Hyman', 'last_name' => 'Lachowsky', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1885-01-01', 'death_date' => '1944-06-15', 'description' => 'Russian-Jewish bookbinder and Frayhayt-group anarchist convicted alongside Jacob Abrams. Eyewitnesses testified he was severely beaten by police during interrogation. Convicted Oct 23, 1918 under the Sedition Act; sentenced to 20 years and $1,000 fine. Deported to Soviet Russia Nov 24, 1921 aboard SS Estonia. Returned to his hometown in present-day Belarus; reported to have perished under Nazi occupation during the Holocaust.', 'affiliation' => ['Frayhayt anarchist group'], 'cases' => [['institution' => ['name' => 'U.S. Penitentiary Atlanta — Abrams trial', 'city' => 'Atlanta', 'state' => 'Georgia'], 'arrest_date' => '1918-08-23', 'sentenced_date' => '1918-10-23', 'release_date' => '1921-11-24', 'sentence' => '20 years federal prison + $1,000 fine; deported Nov 1921', 'convicted' => 'Yes', 'judge' => 'Hon. Henry DeLamar Clayton Jr.', 'charges' => 'Conspiracy to violate Sedition Act of 1918.']]],
    ['name' => 'Samuel Lipman', 'first_name' => 'Samuel', 'last_name' => 'Lipman', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1898-01-01', 'death_date' => '1937-12-15', 'description' => '21 at the time of his arrest; the lone Marxist socialist (rather than anarchist) among the Abrams defendants and a worker in the fur trade. Authored the English-language leaflet — the milder of the two leaflets at issue. Convicted Oct 23, 1918 under the Sedition Act; sentenced to 20 years and $1,000 fine. Deported to Soviet Russia Nov 24, 1921. There became a Communist Party member and economist; arrested in Stalin\'s Great Purge and reportedly executed in 1937.', 'affiliation' => ['Frayhayt group'], 'cases' => [['institution' => ['name' => 'U.S. Penitentiary Atlanta — Abrams trial', 'city' => 'Atlanta', 'state' => 'Georgia'], 'arrest_date' => '1918-08-23', 'sentenced_date' => '1918-10-23', 'release_date' => '1921-11-24', 'sentence' => '20 years federal prison + $1,000 fine; deported Nov 1921', 'convicted' => 'Yes', 'judge' => 'Hon. Henry DeLamar Clayton Jr.', 'charges' => 'Conspiracy to violate Sedition Act of 1918.']]],
    ['name' => 'Carlo Tresca', 'first_name' => 'Carlo', 'last_name' => 'Tresca', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1879-03-09', 'death_date' => '1943-01-11', 'description' => 'Born in Sulmona, Italy 1879; emigrated to U.S. 1904; became prominent IWW organizer (Lawrence 1912, Paterson 1913, Mesabi Range 1916), longtime editor of anti-fascist Italian-language paper Il Martello, and partner of Elizabeth Gurley Flynn. Repeatedly prosecuted during the Wilson era under the Espionage Act and federal obscenity statutes; faced multiple deportation proceedings he successfully resisted. A relentless opponent of Mussolini, Stalin, and Mafia infiltration of unions; assassinated on a Manhattan street corner Jan 11, 1943.', 'affiliation' => ['Industrial Workers of the World', 'Italian Socialist Federation', 'Il Martello (editor)'], 'cases' => [['institution' => ['name' => 'Federal courts (multiple Wilson-era prosecutions of Carlo Tresca)', 'city' => 'New York', 'state' => 'New York'], 'arrest_date' => '1917-06-15', 'sentence' => 'Multiple Espionage Act prosecutions and deportation proceedings, all successfully resisted.', 'convicted' => 'Multiple charges; not deported', 'charges' => 'Various Espionage Act and federal obscenity prosecutions, deportation proceedings.']]],
    ['name' => 'Luigi Galleani', 'first_name' => 'Luigi', 'last_name' => 'Galleani', 'gender' => 'Male', 'race' => 'White', 'state' => 'Massachusetts', 'birthdate' => '1861-08-12', 'death_date' => '1931-11-04', 'description' => 'Leading insurrectionary anarchist theorist among Italian immigrants in early 20th-century America. From June 6, 1903 edited Cronaca Sovversiva ("Subversive Chronicle") in Barre, Vermont and later Lynn, Massachusetts. His followers, the Galleanisti, carried out the 1919 anarchist bombings and the Wall Street bombing of 1920; Sacco and Vanzetti were Galleanisti. Federal agents shut down Cronaca Sovversiva June 17, 1917. Deported to Italy June 24, 1919 along with eight followers (the "Galleani 9"). In Italy repeatedly imprisoned and exiled under Mussolini until his death 1931.', 'affiliation' => ['Cronaca Sovversiva (editor)', 'Galleanisti'], 'cases' => [['institution' => ['name' => 'Immigration Bureau, Ellis Island — Galleani 9 deportation', 'city' => 'New York', 'state' => 'New York'], 'arrest_date' => '1917-06-17', 'release_date' => '1919-06-24', 'sentence' => 'Deported to Italy June 24, 1919 along with 8 followers (the "Galleani 9")', 'convicted' => 'Deported under Immigration Act of 1918 (Anarchist Exclusion)', 'charges' => 'Espionage Act / Immigration Act anarchist deportation proceedings.']]],

    // ===== 4. WWI Conscientious Objectors =====
    ['name' => 'Joseph J. Hofer', 'first_name' => 'Joseph', 'middle_name' => 'J.', 'last_name' => 'Hofer', 'gender' => 'Male', 'race' => 'White', 'state' => 'South Dakota', 'birthdate' => '1894-10-24', 'death_date' => '1918-11-29', 'released' => false, 'description' => 'Hutterite communal farmer from the Rockport Colony in South Dakota, drafted in May 1918 along with his brothers Michael and David and his brother-in-law Jacob Wipf. Refusing on Anabaptist grounds to don the military uniform, court-martialed and sentenced to 20 years hard labor at Alcatraz. After four months of solitary confinement on bread and water and "high cuffing" chains, transferred to Fort Leavenworth on Nov 19, 1918, and died ten days later. The Hutterite Church regards him as a martyr.', 'affiliation' => ['Hutterite', 'Rockport Colony'], 'cases' => [['institution' => ['name' => 'United States Disciplinary Barracks, Fort Leavenworth', 'city' => 'Leavenworth', 'state' => 'Kansas'], 'arrest_date' => '1918-05-25', 'incarceration_date' => '1918-07-27', 'death_in_custody_date' => '1918-11-29', 'sentence' => '20 years hard labor; died in custody', 'convicted' => 'Yes — court-martialed under Articles of War', 'charges' => 'Court-martialed for refusing to obey orders / refusing to wear military uniform.']]],
    ['name' => 'Michael Hofer', 'first_name' => 'Michael', 'last_name' => 'Hofer', 'gender' => 'Male', 'race' => 'White', 'state' => 'South Dakota', 'birthdate' => '1893-07-13', 'death_date' => '1918-12-02', 'released' => false, 'description' => 'Hutterite communal farmer drafted with his brothers Joseph and David and brother-in-law Jacob Wipf in May 1918. After refusing all forms of military service, sentenced to 20 years and shipped in chains to Alcatraz, where the four men endured solitary confinement, dim cells with rationed water, and chained suspension. Transferred to Fort Leavenworth Nov 19, 1918, died Dec 2 — three days after Joseph — officially of pneumonia, but Hutterite tradition holds it was the result of mistreatment. Buried at Rockport Colony beside his brother.', 'affiliation' => ['Hutterite', 'Rockport Colony'], 'cases' => [['institution' => ['name' => 'United States Disciplinary Barracks, Fort Leavenworth', 'city' => 'Leavenworth', 'state' => 'Kansas'], 'arrest_date' => '1918-05-25', 'incarceration_date' => '1918-07-27', 'death_in_custody_date' => '1918-12-02', 'sentence' => '20 years hard labor; died in custody', 'convicted' => 'Yes — court-martialed', 'charges' => 'Court-martialed for refusing to obey orders.']]],
    ['name' => 'David Hofer', 'first_name' => 'David', 'last_name' => 'Hofer', 'gender' => 'Male', 'race' => 'White', 'state' => 'South Dakota', 'birthdate' => '1890-01-01', 'description' => 'Eldest of the four Hutterites drafted from the Rockport Colony in South Dakota in May 1918, was 28 years old when sentenced alongside his younger brothers and brother-in-law to 20 years of hard labor for refusing military duty. Survived Alcatraz and Fort Leavenworth; released shortly after his brothers died in late November/early December 1918, allowed to accompany the bodies home for burial. Joined the migration of Hutterite colonies to Canada to escape American persecution.', 'affiliation' => ['Hutterite', 'Rockport Colony'], 'cases' => [['institution' => ['name' => 'United States Disciplinary Barracks, Fort Leavenworth', 'city' => 'Leavenworth', 'state' => 'Kansas'], 'arrest_date' => '1918-05-25', 'incarceration_date' => '1918-07-27', 'release_date' => '1918-12-15', 'sentence' => '20 years hard labor (released early after brothers\' deaths)', 'convicted' => 'Yes — court-martialed', 'charges' => 'Court-martialed for refusing to obey orders.']]],
    ['name' => 'Jacob Wipf', 'first_name' => 'Jacob', 'last_name' => 'Wipf', 'gender' => 'Male', 'race' => 'White', 'state' => 'South Dakota', 'birthdate' => '1888-01-01', 'description' => 'Brother-in-law of Joseph Hofer; 30 years old, married with three children, when drafted from the Rockport Hutterite Colony in South Dakota May 25, 1918. As the eldest of the four-man Hutterite group sent to Alcatraz, bore the brunt of ordering refusals on behalf of the others; after his three companions were transferred to Leavenworth and the Hofer brothers died, he alone remained imprisoned for an additional five months. Released April 13, 1919.', 'affiliation' => ['Hutterite', 'Rockport Colony'], 'cases' => [['institution' => ['name' => 'United States Disciplinary Barracks, Fort Leavenworth', 'city' => 'Leavenworth', 'state' => 'Kansas'], 'arrest_date' => '1918-05-25', 'incarceration_date' => '1918-07-27', 'release_date' => '1919-04-13', 'sentence' => '20 years hard labor (released early)', 'convicted' => 'Yes — court-martialed', 'charges' => 'Court-martialed for refusing to obey orders.']]],
    ['name' => 'Roger Nash Baldwin', 'first_name' => 'Roger', 'middle_name' => 'Nash', 'last_name' => 'Baldwin', 'gender' => 'Male', 'race' => 'White', 'state' => 'New Jersey', 'birthdate' => '1884-01-21', 'death_date' => '1981-08-26', 'description' => 'Harvard-educated social worker who, after the U.S. entered WWI, became director of the American Union Against Militarism\'s Civil Liberties Bureau — soon spun off as the National Civil Liberties Bureau, the direct predecessor of the ACLU. Refused induction October 1918, read his celebrated statement "The Individual and the State" in court; sentenced to eleven months in prison, served nine before his release in July 1919. Co-founded ACLU January 1920; led it for three decades; awarded Presidential Medal of Freedom by Carter 1981.', 'affiliation' => ['National Civil Liberties Bureau', 'ACLU (co-founder, 1920)'], 'cases' => [['institution' => ['name' => 'Essex County Jail', 'city' => 'Newark', 'state' => 'New Jersey'], 'arrest_date' => '1918-10-20', 'incarceration_date' => '1918-10-30', 'release_date' => '1919-07-15', 'sentence' => '11 months (served 9)', 'convicted' => 'Yes', 'charges' => 'Violation of the Selective Service Act — refusing induction.']]],
    ['name' => 'Evan Welling Thomas', 'first_name' => 'Evan', 'middle_name' => 'Welling', 'last_name' => 'Thomas', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1890-01-01', 'death_date' => '1974-12-15', 'description' => 'Younger brother of Norman Thomas; Princeton seminary student studying in Edinburgh when the U.S. entered WWI; returned home and refused induction as an absolutist conscientious objector. After leading a hunger strike at Fort Riley, Kansas in August 1918, court-martialed, sentenced to life imprisonment, transferred to Fort Leavenworth, where held in solitary confinement and chained handcuffed to his cell door for 14 days. Sentence commuted; released 1919. Later trained as a physician, chaired the War Resisters League for many years.', 'affiliation' => ['Christian pacifist', 'War Resisters League (later)'], 'cases' => [['institution' => ['name' => 'United States Disciplinary Barracks, Fort Leavenworth', 'city' => 'Leavenworth', 'state' => 'Kansas'], 'arrest_date' => '1918-08-15', 'incarceration_date' => '1918-09-15', 'release_date' => '1919-09-15', 'sentence' => 'Life imprisonment (commuted)', 'convicted' => 'Yes — court-martialed', 'charges' => 'Court-martialed under the Articles of War — refusing orders / leading hunger strike.']]],
    ['name' => 'Howard Wilbur Moore', 'first_name' => 'Howard', 'middle_name' => 'Wilbur', 'last_name' => 'Moore', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1889-01-01', 'death_date' => '1993-07-15', 'description' => 'New York farm laborer drafted in 1918 and sent to Camp Upton on April 29; refusing the uniform, was among about fifty-five "absolutists" transferred through Fort Riley and Camp Funston before arriving at Fort Leavenworth Disciplinary Barracks Armistice Day, November 11, 1918. Court-martialed and sentenced to five years\' hard labor; beaten, hung by his thumbs, locked in vermin-infested cells, fed garbage, personally berated by visiting General John J. Pershing. Last absolutist released in late 1920. At age 95 wrote the lyrical memoir "Plowing My Own Furrow" (1985).', 'affiliation' => ['Absolutist conscientious objector'], 'cases' => [['institution' => ['name' => 'United States Disciplinary Barracks, Fort Leavenworth', 'city' => 'Leavenworth', 'state' => 'Kansas'], 'arrest_date' => '1918-04-29', 'incarceration_date' => '1918-11-11', 'release_date' => '1920-12-15', 'sentence' => '5 years hard labor', 'convicted' => 'Yes — court-martialed', 'charges' => 'Court-martialed under the Articles of War — refusing orders / refusing the uniform.']]],
    ['name' => 'Harold Studley Gray', 'first_name' => 'Harold', 'middle_name' => 'Studley', 'last_name' => 'Gray', 'gender' => 'Male', 'race' => 'White', 'state' => 'Michigan', 'birthdate' => '1894-01-01', 'death_date' => '1972-12-15', 'description' => 'Son of a wealthy Detroit family, left Harvard in his sophomore year to serve as a YMCA secretary in England, but resigned in 1917 when YMCA was militarized. Court-martialed for disobedience, sentenced to 25 years (later reduced to three), held first at Fort Leavenworth and then at Alcatraz, where he participated in a publicized hunger strike and was force-fed. Sentence remitted Aug 19, 1919 on the basis of "sincere" objection. Prison letters published 1934 as "Character Bad": The Story of a Conscientious Objector.', 'affiliation' => ['Religious Society of Friends (Quaker)', 'YMCA (former)'], 'cases' => [['institution' => ['name' => 'Alcatraz Military Prison', 'city' => 'San Francisco', 'state' => 'California'], 'arrest_date' => '1918-06-15', 'incarceration_date' => '1918-07-18', 'release_date' => '1919-08-19', 'sentence' => '25 years (reduced to 3; remitted)', 'convicted' => 'Yes — court-martialed', 'charges' => 'Court-martialed under the Articles of War — disobedience of orders.']]],
    ['name' => 'Benjamin Joseph Salmon', 'first_name' => 'Benjamin', 'middle_name' => 'Joseph', 'last_name' => 'Salmon', 'aka' => 'Ben Salmon', 'gender' => 'Male', 'race' => 'White', 'state' => 'Colorado', 'birthdate' => '1889-10-15', 'death_date' => '1932-02-15', 'description' => 'Denver-born Catholic clerk and early activist for the Knights of Columbus and Catholic labor causes who, on June 5, 1917, wrote directly to President Wilson refusing to register for the draft on the grounds that all war was incompatible with the teachings of Christ. As one of only a handful of identifiable Catholic absolutists, charged with desertion and "spreading propaganda," sentenced to death (commuted to 25 years hard labor). Spent six months in "the hole" — a windowless 5×9 cell over the prison sewer; endured beatings, force-feeding, and a 135-day hunger strike. Released in Thanksgiving 1920 clemency. His ordeal permanently broke his health; died of pneumonia 1932 at age 43; cause for sainthood opened by Catholic Diocese of Denver in 2017.', 'affiliation' => ['Roman Catholic Church'], 'cases' => [['institution' => ['name' => 'United States Disciplinary Barracks, Fort Leavenworth', 'city' => 'Leavenworth', 'state' => 'Kansas'], 'arrest_date' => '1918-01-15', 'incarceration_date' => '1918-07-15', 'release_date' => '1920-11-26', 'sentence' => 'Death (commuted to 25 years hard labor)', 'convicted' => 'Yes — court-martialed', 'charges' => 'Court-martialed under the Articles of War — desertion and spreading propaganda.']]],
    ['name' => 'Philip Grosser', 'first_name' => 'Philip', 'last_name' => 'Grosser', 'gender' => 'Male', 'race' => 'White', 'state' => 'Massachusetts', 'birthdate' => '1890-01-01', 'death_date' => '1933-10-15', 'description' => 'Born in Slavuta, Ukraine 1890; established anarchist activist in Boston by 1917; among the first to refuse the draft on political — rather than religious — grounds. Court-martialed and sent to Alcatraz; refused the uniform, refused to stand in formation, and refused "hard labor"; retaliated against with extended solitary, beatings, being dragged on a rope, denial of toilet facilities, and confinement in Alcatraz\'s "iron maidens" (upright iron cages). After release wrote one of the earliest published exposés of conditions at Alcatraz, the 32-page pamphlet "Alcatraz – Uncle Sam\'s Devil\'s Island" (1933). Took his own life in Boston Oct 1933.', 'affiliation' => ['Anarchist movement (Boston)'], 'cases' => [['institution' => ['name' => 'Alcatraz Military Prison', 'city' => 'San Francisco', 'state' => 'California'], 'arrest_date' => '1917-08-15', 'incarceration_date' => '1918-01-15', 'release_date' => '1920-12-15', 'sentence' => 'Multi-year hard labor at Alcatraz', 'convicted' => 'Yes — court-martialed', 'charges' => 'Court-martialed under the Articles of War — refusing orders / refusing the uniform.']]],
    ['name' => 'Joseph Franklin Rutherford', 'first_name' => 'Joseph', 'middle_name' => 'Franklin', 'last_name' => 'Rutherford', 'aka' => 'Judge Rutherford', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1869-11-08', 'death_date' => '1942-01-08', 'description' => 'Missouri-born lawyer; successor to Charles Taze Russell as president of the Watch Tower Bible and Tract Society. Lead defendant in the May 1918 federal indictment of eight Watch Tower directors known as the "Rutherford 8" — charged under the Espionage Act of 1917 with attempting to cause insubordination by distributing the millenarian book The Finished Mystery. After trial in EDNY (Brooklyn), jury convicted June 20, 1918; Judge Harland B. Howe imposed 20-year sentences June 21. Defendants entered the U.S. Penitentiary at Atlanta; served roughly nine months, released on bail March 1919 after Justice Brandeis granted relief. Convictions reversed on appeal 1919; charges dropped 1920. Renamed the movement "Jehovah\'s Witnesses" in 1931.', 'affiliation' => ['Watch Tower Society / Jehovah\'s Witnesses (President)'], 'cases' => [['institution' => ['name' => 'U.S. Penitentiary Atlanta — Rutherford 8 Watch Tower trial', 'city' => 'Atlanta', 'state' => 'Georgia'], 'arrest_date' => '1918-05-08', 'sentenced_date' => '1918-06-21', 'release_date' => '1919-03-26', 'sentence' => '20 years federal prison; conviction reversed on appeal 1919; charges dropped 1920', 'convicted' => 'Yes; reversed on appeal', 'judge' => 'Hon. Harland B. Howe', 'charges' => 'Espionage Act of 1917 — conspiring to cause insubordination, disloyalty, and refusal of duty in the armed forces (publication of The Finished Mystery).']]],
    ['name' => 'William E. Van Amburgh', 'first_name' => 'William', 'middle_name' => 'E.', 'last_name' => 'Van Amburgh', 'gender' => 'Male', 'race' => 'White', 'state' => 'New York', 'birthdate' => '1864-01-01', 'death_date' => '1947-12-15', 'description' => 'Secretary-treasurer of the Watch Tower Bible and Tract Society and one of eight Watch Tower directors indicted May 7, 1918 under the Espionage Act for the publication of The Finished Mystery. Tried alongside Joseph Rutherford in Brooklyn; convicted June 20, 1918; sentenced to 20 years; incarcerated at U.S. Penitentiary Atlanta. Released on bail March 1919 after Justice Brandeis intervened; conviction reversed on appeal 1919.', 'affiliation' => ['Watch Tower Society'], 'cases' => [['institution' => ['name' => 'U.S. Penitentiary Atlanta — Rutherford 8 Watch Tower trial', 'city' => 'Atlanta', 'state' => 'Georgia'], 'arrest_date' => '1918-05-08', 'sentenced_date' => '1918-06-21', 'release_date' => '1919-03-26', 'sentence' => '20 years federal prison; reversed on appeal', 'convicted' => 'Yes; reversed', 'judge' => 'Hon. Harland B. Howe', 'charges' => 'Espionage Act of 1917 — distribution of The Finished Mystery.']]],
    ['name' => 'Clayton J. Woodworth', 'first_name' => 'Clayton', 'middle_name' => 'J.', 'last_name' => 'Woodworth', 'gender' => 'Male', 'race' => 'White', 'state' => 'Pennsylvania', 'birthdate' => '1870-01-01', 'death_date' => '1951-12-15', 'description' => 'Primary co-author of The Finished Mystery (1917). Indicted with Joseph Rutherford and six other Watch Tower leaders May 1918 for the very book he had helped write. Convicted Espionage Act June 20, 1918; received 20-year sentence; sent to federal penitentiary in Atlanta; served nine months before being released on bail March 1919. Founding editor of the Watch Tower magazine The Golden Age (later Awake!) which he edited 1919-1946.', 'affiliation' => ['Watch Tower Society'], 'cases' => [['institution' => ['name' => 'U.S. Penitentiary Atlanta — Rutherford 8 Watch Tower trial', 'city' => 'Atlanta', 'state' => 'Georgia'], 'arrest_date' => '1918-05-08', 'sentenced_date' => '1918-06-21', 'release_date' => '1919-03-26', 'sentence' => '20 years federal prison; reversed on appeal', 'convicted' => 'Yes; reversed', 'judge' => 'Hon. Harland B. Howe', 'charges' => 'Espionage Act of 1917 — co-authorship and distribution of The Finished Mystery.']]],
