$nwpInst = ['name' => 'Occoquan Workhouse / DC Jail — Silent Sentinels', 'city' => 'Lorton', 'state' => 'Virginia'];
$nwpChargesBase = 'National Woman\'s Party "Silent Sentinels" picketing of the Wilson White House (Jan 10, 1917 - June 1919). ~2,000 women picketed; ~500 arrested; 168 jailed at Occoquan Workhouse (Lorton VA) and DC Jail. Charges typically "obstructing sidewalk traffic" — pretextual misdemeanor. The "Night of Terror" Nov 14, 1917 saw guards beat 33 newly arrived suffragists. Many were force-fed during hunger strikes.';

$sentinels = [
    ['Alice Stokes Paul', '1885-01-11', '1977-07-09', '1917-10-20', '7 months', '1917-11-27', 'Founder of the National Woman\'s Party and chief strategist of the militant U.S. suffrage movement. A Hicksite Quaker from Mount Laurel, New Jersey; PhD in economics (Penn 1912); apprenticed in militant tactics with Emmeline Pankhurst\'s WSPU in Britain. Beginning January 10, 1917, organized the "Silent Sentinels" picketing. After Oct 20, 1917 arrest, sentenced to seven months and led hunger strikes at the District Jail; authorities transferred her to a psychiatric ward and force-fed her raw eggs through a feeding tube three times daily. Authored the original Equal Rights Amendment in 1923.', ['National Woman\'s Party (founder)', 'Religious Society of Friends']],
    ['Lucy Burns', '1879-07-28', '1966-12-22', '1917-09-04', '6 months (max on third arrest)', null, 'Alice Paul\'s closest collaborator in the National Woman\'s Party; suffragist who served the most prison time of any American woman in the campaign. Vassar 1902; born in Brooklyn to an Irish Catholic family. On the November 14, 1917 "Night of Terror" she was beaten at Occoquan and chained by her wrists to her cell bars overnight; later force-fed via nasal tube by five guards. After ratification she retired to Brooklyn.', ['National Woman\'s Party']],
    ['Vida Milholland', '1888-01-17', '1952-06-15', '1917-07-04', '3 days', null, 'Younger sister of Inez Milholland; Vassar-trained singer who abandoned her musical career after Inez\'s death to take up full-time suffrage work. Picketed the White House on July 4, 1917, was arrested, served three days in DC Jail singing every night for the morale of fellow prisoners. In 1919 joined the NWP\'s "Prison Special" national tour.', ['National Woman\'s Party']],
    ['Lavinia Lloyd Dock', '1858-02-26', '1956-04-17', '1917-08-15', null, null, 'Pioneer of American nursing — co-founder of what became the National League for Nursing, author of the first nurses\' drug manual (1890). In 1917 moved to Washington and joined the advisory council of the National Woman\'s Party. First arrested in 1896 attempting to vote. As a Silent Sentinel arrested at least three times in 1917 and served sentences at Occoquan. In her late 50s, among the older suffragists imprisoned.', ['National Woman\'s Party', 'American Nurses Association']],
    ['Doris Stevens', '1888-10-26', '1963-03-22', '1917-07-14', '60 days (pardoned after 3)', '1917-07-17', 'Oberlin-trained organizer (1911); served as executive secretary of the Congressional Union and a key NWP strategist. Born in Omaha to a pastor and a Dutch immigrant mother. Picketed the White House on Bastille Day July 14, 1917 with fifteen others; sentenced to 60 days at Occoquan; served three days before President Wilson pardoned the group. Her 1920 book "Jailed for Freedom" is the principal firsthand account of NWP imprisonment.', ['National Woman\'s Party', 'Congressional Union for Woman Suffrage']],
    ['Helena Hill Weed', '1875-08-16', '1958-04-20', '1917-07-04', '3 days (1917); 24 hours (Jan 1918); 15 days (Aug 1918)', null, 'Daughter of U.S. Congressman Ebenezer J. Hill; Vassar graduate (1896); one of the first women geologists in the United States. On July 4, 1917 picketed the White House with a banner reading "Governments derive their just powers from the consent of the governed"; sentenced to three days in jail. Arrested again in January 1918 (24-hour sentence for applauding in court) and August 1918 (15 days for the Lafayette Square meeting where Wilson\'s words were ceremonially burned).', ['National Woman\'s Party']],
    ['Annie Melvin Arniel', '1873-05-15', '1924-02-09', '1917-06-27', 'Multiple, totaling 103 days', null, 'Wilmington factory worker recruited to the NWP by Mabel Vernon and Alice Paul; one of Delaware\'s most-jailed suffragists. Among the first six suffragists arrested at the White House on June 27, 1917; served eight separate jail terms totaling 103 days, including 60 days at Occoquan in 1917, 15 days for the Lafayette Square meeting in 1918, and five 5-day sentences during the 1919 "watchfire" demonstrations.', ['National Woman\'s Party']],
    ['Edith Mary Ainge', '1873-09-10', '1948-10-25', '1917-09-04', null, null, 'English-born Jamestown, NY suffragist who served as treasurer of the National Woman\'s Party. First arrested September 4, 1917 — the "March of Draftees" day — for unfurling a banner reading "How Long Must Woman Be Denied a Voice in a Government Which is Conscripting Their Sons." Arrested approximately five times between September 1917 and January 1919.', ['National Woman\'s Party']],
    ['Mary A. Nolan', '1842-01-15', '1925-05-19', '1917-11-10', '6 days', null, '73-year-old Jacksonville suffragist — the oldest known prisoner of the campaign and the only Floridian imprisoned for suffrage. Born in Martinsburg, Virginia (later WV) in 1842; joined the NWP in 1917; arrested November 10, 1917 along with 30 other picketers. Given the lightest sentence (six days) on account of her age; sent to Occoquan and witnessed the Night of Terror. Her published narrative "That Night of Terror" triggered the firing of Superintendent W.H. Whittaker.', ['National Woman\'s Party']],
    ['Dora Kelly Lewis', '1862-10-13', '1928-01-31', '1917-11-10', '60 days (Night of Terror cohort)', null, 'Philadelphia widow from a prominent family who became one of Alice Paul\'s earliest and most steadfast supporters, joining the Congressional Union at its 1913 founding. On the November 14, 1917 Night of Terror, thrown into a tiny Occoquan cell, struck her head on an iron bedstead and lost consciousness; her cellmate Alice Cosu suffered a heart attack believing Lewis was dead. With Lucy Burns led the prisoners\' hunger strike and endured force-feeding "gasping and suffocating with the agony of it."', ['National Woman\'s Party']],
    ['Pauline Forstall Adams', '1874-06-29', '1957-09-10', '1917-09-04', '60 days', '1917-11-04', 'Dublin-born suffragist who emigrated to the U.S. in 1898 and founded the Norfolk Equal Suffrage League at her home in 1910. On September 4, 1917 was one of thirteen NWP picketers arrested in front of Wilson\'s reviewing stand at the Selective Service parade. Refusing the $25 fine, chose 60 days at Occoquan; released November 4, 1917. After ratification became the second woman to practice law in Norfolk (1921).', ['National Woman\'s Party', 'Norfolk Equal Suffrage League (founder)']],
    ['Elizabeth Selden Rogers', '1868-07-23', '1950-12-18', '1917-07-14', '60 days (pardoned by Wilson within days)', null, 'New York civic reformer and Putnam County NWP leader. On Bastille Day July 14, 1917 was one of 16 Silent Sentinels arrested at the White House carrying a banner with the French motto "Liberty, Equality, Fraternity." Told the judge, "We know full well that we stand here because the President of the United States refuses to give liberty to American women." Sentenced to 60 days; pardoned by Wilson within days.', ['National Woman\'s Party', 'Women\'s Political Union']],
